+
+    const ranges: Array<{ offset: number; limit: number }> = [];
+
+    for (
+      let chunk = Math.floor(start / this.CHUNK_SIZE) * this.CHUNK_SIZE;
+      chunk < end;
+      chunk += this.CHUNK_SIZE
