+    // Build SVG path
+    const width = 80;
+    const step = width / (normalized.length - 1 || 1);
+    let path = `M0,${normalized[0].toFixed(1)}`;
+    for (let i = 1; i < normalized.length; i++) {
+      path += ` L${(i * step).toFixed(1)},${normalized[i].toFixed(1)}`;
+    }
