+/* LanceQL Virtual Table Styles */
+
+.lanceql-virtual-table {
+  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
+  font-size: 13px;
+  line-height: 1.4;
+}
+
+.lq-container {
+  border: 1px solid var(--jp-border-color1, #e0e0e0);
+  border-radius: 4px;
+  overflow: hidden;
+  background: var(--jp-layout-color0, #fff);
+}
+
+/* Header */
+.lq-header {
+  display: flex;
+  background: var(--jp-layout-color2, #f5f5f5);
+  font-weight: 600;
+  border-bottom: 1px solid var(--jp-border-color1, #e0e0e0);
+  position: sticky;
+  top: 0;
+  z-index: 10;
+}
+
+.lq-header .lq-cell {
+  padding: 8px 12px;
+  color: var(--jp-ui-font-color1, #333);
+  display: flex;
+  flex-direction: column;
+  gap: 4px;
+}
+
+.lq-col-name {
+  font-weight: 600;
+}
+
+/* Type badges */
+.lq-type-badge {
+  display: inline-block;
+  font-size: 10px;
+  font-weight: 500;
+  padding: 1px 6px;
+  border-radius: 3px;
+  text-transform: uppercase;
+  letter-spacing: 0.3px;
+  width: fit-content;
+}
+
+.lq-type-vector {
+  background: linear-gradient(135deg, #6366f1, #8b5cf6);
+  color: white;
+}
+
+.lq-type-string {
+  background: #10b981;
+  color: white;
+}
+
+.lq-type-int {
